// Lấy input theo đúng tên node
const sales30d = $items("filter_1");
const oosItems = $items("oos");
const inventoryItems = $items("get_inv");

// Map sales theo sku
const salesMap = {};
for (const item of sales30d) {
  salesMap[item.json.sku] = {
    sku: item.json.sku,
    sku_name: item.json.sku_name,
    sales: Number(item.json.qty || 0),
  };
}

// Map OOS theo sku
const oosSet = new Set();
for (const item of oosItems) {
  oosSet.add(item.json.sku);
}

// Group inventory theo sku
const inventoryMap = {};
for (const item of inventoryItems) {
  const sku = item.json.sku;
  if (!inventoryMap[sku]) inventoryMap[sku] = [];
  inventoryMap[sku].push(item.json);
}

// Xử lý logic
const result = [];

for (const sku in salesMap) {
  const { sku_name, sales } = salesMap[sku];
  const inventories = inventoryMap[sku] || [];

  const totalStock = inventories.reduce((sum, i) => sum + Number(i.qty || 0), 0);

  const displayZoneStock = inventories.filter(
    i => i.zone === "Trưng bày chỉ định" && Number(i.qty || 0) > 0
  );

  const otherZoneStock = inventories.filter(
    i => i.zone !== "Trưng bày chỉ định" && Number(i.qty || 0) > 0
  );

  let outputQty = 0;
  let ruleApplied = null;

  // Rule 3: chỉ có tồn kho ở Trưng bày chỉ định
  if (displayZoneStock.length > 0 && otherZoneStock.length === 0) {
    outputQty = 2;
    ruleApplied = "ONLY_DISPLAY_ZONE";
  }
  // Rule 1: có OOS
  else if (oosSet.has(sku)) {
    outputQty = Math.max(Math.floor(sales / 4), 1);
    ruleApplied = "OOS";
  }
  // Rule 2: có bán và tồn kho <= 1
  else if (sales > 0 && totalStock <= 1) {
    outputQty = Math.max(Math.floor(sales / 4), 1);
    ruleApplied = "LOW_STOCK_WITH_SALES";
  }

  if (outputQty > 0) {
    result.push({
      json: {
        sku,
        sku_name,
        qty: outputQty,
        rule: ruleApplied,
        sales_30d: sales,
        total_stock: totalStock,
      }
    });
  }
}

return result;

